import React, { useState } from 'react';
import CreateCampaign from './CreateCampaign';
import SubscriberList from './SubscriberList';
import { Subscriber, NewsletterCampaign } from '../types';

interface BusinessToolsProps {
  campaigns: NewsletterCampaign[];
  subscribers: Subscriber[];
  onSaveCampaign: (c: any) => void;
  onDeleteSubscriber: (id: string) => void;
}

const BusinessTools: React.FC<BusinessToolsProps> = ({ campaigns, subscribers, onSaveCampaign, onDeleteSubscriber }) => {
  const [activeTab, setActiveTab] = useState<'NEWSLETTER' | 'SUBSCRIBERS'>('NEWSLETTER');

  return (
    <div className="space-y-12 py-8">
      <header className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div>
          <h2 className="text-4xl font-bold text-slate-900 serif italic">Seed to Paradise</h2>
          <p className="text-slate-500 mt-2 font-light tracking-wide uppercase text-[10px]">Flagship Newsletter & CRM Suite</p>
        </div>
        <div className="flex bg-slate-200/50 p-1 rounded-2xl border border-slate-200">
           <button 
             onClick={() => setActiveTab('NEWSLETTER')}
             className={`px-6 py-2 rounded-xl text-xs font-bold transition-all ${activeTab === 'NEWSLETTER' ? 'bg-white text-amber-800 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
           >
             Newsletter Engine
           </button>
           <button 
             onClick={() => setActiveTab('SUBSCRIBERS')}
             className={`px-6 py-2 rounded-xl text-xs font-bold transition-all ${activeTab === 'SUBSCRIBERS' ? 'bg-white text-amber-800 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
           >
             Community Insights
           </button>
        </div>
      </header>

      {activeTab === 'NEWSLETTER' ? (
        <CreateCampaign onSave={onSaveCampaign} />
      ) : (
        <SubscriberList subscribers={subscribers} onDelete={onDeleteSubscriber} />
      )}
    </div>
  );
};

export default BusinessTools;
