import React, { useState } from 'react';
import { generateNewsletterContent } from '../services/geminiService';
import { GenerationConfig } from '../types';

interface CreateCampaignProps {
  onSave: (campaign: any) => void;
}

const CreateCampaign: React.FC<CreateCampaignProps> = ({ onSave }) => {
  const [loading, setLoading] = useState(false);
  const [config, setConfig] = useState<GenerationConfig>({
    topic: 'The Intersection of Audio and Botanical Luxury',
    tone: 'Elegant & Inspiring',
    includeOffer: true,
    audienceType: 'Artists & Curators'
  });
  const [generatedContent, setGeneratedContent] = useState('');
  const [subject, setSubject] = useState('');

  const handleGenerate = async () => {
    setLoading(true);
    try {
      const result = await generateNewsletterContent(config);
      const lines = result.split('\n');
      const subjectLine = lines.find(l => l.toLowerCase().includes('subject:'))?.replace(/Subject:/i, '').trim() || 'A SpectroModel Exclusive';
      setSubject(subjectLine);
      setGeneratedContent(result);
    } catch (err) {
      alert("Unable to generate. Check system status.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="max-w-7xl mx-auto space-y-8 animate-fadeIn py-4">
      <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
        {/* Editor Settings */}
        <div className="lg:col-span-4 space-y-6 bg-white p-8 rounded-[2rem] border border-slate-100 shadow-sm h-fit">
          <header className="border-b border-slate-100 pb-4 mb-4">
             <h3 className="text-xl font-bold text-slate-900 serif italic">Content Architect</h3>
             <p className="text-[8px] text-amber-700 font-bold uppercase tracking-widest">SpectroModel Studio</p>
          </header>

          <div>
            <label className="block text-[10px] font-bold uppercase tracking-widest text-slate-400 mb-2">Subject Context / Topic</label>
            <textarea
              className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-amber-500 outline-none text-slate-900 font-medium transition-all placeholder:text-slate-300"
              rows={4}
              value={config.topic}
              onChange={(e) => setConfig({ ...config, topic: e.target.value })}
              placeholder="What narrative are we crafting today?"
            />
          </div>

          <div>
            <label className="block text-[10px] font-bold uppercase tracking-widest text-slate-400 mb-2">Editorial Tone</label>
            <select
              className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-amber-500 outline-none text-slate-900 font-medium transition-all"
              value={config.tone}
              onChange={(e) => setConfig({ ...config, tone: e.target.value })}
            >
              <option>Elegant & Inspiring</option>
              <option>High-End Analytical</option>
              <option>Casual & Personal</option>
              <option>Brand Statement</option>
            </select>
          </div>

          <div className="pt-4 space-y-3">
             <button
              onClick={handleGenerate}
              disabled={loading}
              className={`w-full py-4 rounded-xl font-bold text-xs uppercase tracking-widest text-white transition-all shadow-xl active:scale-95 ${
                loading ? 'bg-amber-800/50' : 'bg-amber-700 hover:bg-amber-800 shadow-amber-200'
              }`}
            >
              {loading ? 'Synthesizing...' : 'Draft with AI'}
            </button>
            <p className="text-[10px] text-center text-slate-400 font-light italic">Or start typing directly in the draft window.</p>
          </div>

          <div className="pt-8 border-t border-slate-100 text-center flex flex-col items-center gap-4">
             <a 
               href="https://spectromodel.com/Landing" 
               target="_blank"
               className="text-amber-800 text-[10px] font-bold uppercase tracking-widest hover:underline inline-flex items-center gap-2"
             >
               Visit Community Landing <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M10 6H6a2 2 0 00-2 2v10a2 2 0 002 2h10a2 2 0 002-2v-4M14 4h6m0 0v6m0-6L10 14" /></svg>
             </a>
             <div className="p-4 bg-slate-50 rounded-2xl w-full">
                <p className="text-[9px] text-slate-500 uppercase tracking-widest font-bold mb-2">Subscribe Module</p>
                <div className="flex gap-2">
                   <input type="text" placeholder="your@email.com" className="bg-white border border-slate-200 rounded-lg px-2 py-1 text-[10px] flex-1 text-slate-900" />
                   <button className="bg-slate-900 text-white px-2 py-1 rounded-lg text-[8px] font-bold uppercase">Join</button>
                </div>
             </div>
          </div>
        </div>

        {/* Content Viewer */}
        <div className="lg:col-span-8">
          <div className="bg-white rounded-[2rem] border border-slate-100 shadow-sm overflow-hidden flex flex-col">
            <div className="bg-slate-50 p-6 border-b border-slate-200">
              <div className="flex items-center gap-4">
                <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest whitespace-nowrap">Newsletter Subject:</span>
                <input 
                  type="text"
                  className="bg-transparent border-none focus:ring-0 text-lg font-bold text-slate-900 w-full placeholder:text-slate-300"
                  value={subject}
                  onChange={(e) => setSubject(e.target.value)}
                  placeholder="Enter a compelling subject..."
                />
              </div>
            </div>

            <div className="p-10 min-h-[600px] flex flex-col bg-[#fcfbf7]/30">
              <div className="mb-12 text-center border-b border-slate-100 pb-10">
                <h1 className="text-4xl font-bold italic serif text-slate-900">Seed to Paradise</h1>
                <p className="text-[10px] uppercase tracking-[0.3em] text-amber-700 font-bold mt-2">Curated by SpectroModel</p>
              </div>

              <div className="flex-1">
                <textarea 
                  className="w-full bg-transparent border-none focus:ring-0 prose prose-slate max-w-none text-slate-800 leading-relaxed font-light min-h-[500px] placeholder:text-slate-200"
                  value={generatedContent}
                  onChange={(e) => setGeneratedContent(e.target.value)}
                  placeholder="Your creative content flows here. Write, edit, and orchestrate..."
                />
              </div>

              <div className="mt-12 pt-10 border-t border-slate-100 text-center space-y-6">
                 <div className="max-w-md mx-auto space-y-2">
                    <p className="text-[10px] text-slate-400 font-light italic">This is an automated distribution from the SpectroModel Platform.</p>
                    <p className="text-[10px] text-slate-900 font-bold tracking-widest uppercase">Visit Landing to Subscribe: spectromodel.com/Landing</p>
                 </div>
                 <div className="flex justify-center gap-8">
                    <a href="https://spectromodel.com/Landing" className="text-amber-800 text-[10px] font-bold uppercase tracking-widest hover:underline">Manage Subscription</a>
                    <a href="#" className="text-slate-400 text-[10px] font-bold uppercase tracking-widest hover:underline">Privacy Preference</a>
                 </div>
              </div>
            </div>

            <div className="p-6 bg-slate-50 border-t border-slate-200 flex justify-between items-center">
              <button 
                className="text-[10px] font-bold text-slate-500 hover:text-rose-600 transition-colors uppercase tracking-widest"
                onClick={() => { setGeneratedContent(''); setSubject(''); }}
              >
                Clear Workspace
              </button>
              <div className="flex gap-3">
                <button className="px-6 py-2 bg-white border border-slate-200 rounded-xl text-[10px] font-bold uppercase tracking-widest text-slate-600 hover:shadow-md transition-all">Export Report</button>
                <button 
                  className="px-8 py-2 bg-slate-900 text-white rounded-xl text-[10px] font-bold uppercase tracking-widest hover:bg-black shadow-xl transition-all disabled:opacity-50"
                  disabled={!generatedContent && !subject}
                  onClick={() => onSave({ title: config.topic, subject, content: generatedContent })}
                >
                  Finalize & Archive
                </button>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default CreateCampaign;
