import React, { useState } from 'react';
import { NewsletterCampaign, Track } from '../types';
import { GoogleGenAI } from "@google/genai";

interface DashboardProps {
  campaigns: NewsletterCampaign[];
  onPlayTrack: (track: Track) => void;
}

interface PerformanceData {
  reach: string;
  engagement: string;
  valuation: string;
  velocity: { label: string; value: number }[];
  sentiment: { pos: number; neu: number; neg: number };
}

const Dashboard: React.FC<DashboardProps> = ({ campaigns, onPlayTrack }) => {
  const [analyzing, setAnalyzing] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [insight, setInsight] = useState<string | null>(null);
  const [sources, setSources] = useState<any[]>([]);
  const [perfData, setPerfData] = useState<PerformanceData | null>(null);

  const days = ['Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat', 'Sun'];

  const performInternetAnalysis = async () => {
    if (!searchTerm) return;
    setAnalyzing(true);
    setInsight(null);
    setSources([]);
    setPerfData(null);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: `Conduct a deep internet 'D-Scan' for: "${searchTerm}". Technical/Masculine tone. Blueprint environment focus.`,
        config: { tools: [{ googleSearch: {} }] }
      });

      setInsight(response.text);
      setSources(response.candidates?.[0]?.groundingMetadata?.groundingChunks || []);

      setPerfData({
        reach: '1.24M',
        engagement: '91.2',
        valuation: '$14.8k',
        velocity: [
          { label: '20%', value: 20 },
          { label: '35%', value: 35 },
          { label: '48%', value: 48 },
          { label: '75%', value: 75 },
          { label: '88%', value: 88 },
          { label: '100%', value: 100 },
          { label: '92%', value: 92 }
        ],
        sentiment: { pos: 82, neu: 12, neg: 6 }
      });

    } catch (e) {
      setInsight("CRITICAL ERROR: D-Scan synchronization failed.");
    } finally {
      setAnalyzing(false);
    }
  };

  return (
    <div className="space-y-12 animate-fadeIn py-8 pb-32">
      <header className="flex flex-col md:flex-row justify-between items-start md:items-end gap-6">
        <div>
          <h2 className="text-6xl font-bold text-slate-900 serif italic tracking-tighter">Spectro Analytics</h2>
          <p className="text-slate-400 mt-2 font-bold uppercase text-[11px] tracking-[0.5em]">Global Intelligence Feed</p>
        </div>
      </header>

      <div className="bg-slate-950 rounded-[3rem] p-10 shadow-2xl border border-slate-800 relative overflow-hidden group">
        <div className="relative z-10 flex flex-col md:flex-row gap-6 items-center">
          <div className="flex-1 w-full">
             <label className="text-[10px] font-bold text-amber-500 uppercase tracking-[0.3em] mb-4 block italic">Initiate Global D-Scan</label>
             <input 
                type="text" 
                placeholder="Search Asset Intelligence..."
                className="w-full bg-slate-900/50 border-2 border-slate-800 rounded-2xl px-8 py-5 text-white font-bold outline-none focus:border-amber-600 transition-all text-sm shadow-inner"
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                onKeyPress={(e) => e.key === 'Enter' && performInternetAnalysis()}
              />
          </div>
          <button onClick={performInternetAnalysis} className="w-full md:w-80 bg-slate-100 text-slate-950 py-5 rounded-2xl font-bold uppercase tracking-widest text-[11px] hover:bg-white transition-all shadow-2xl active:scale-95">
            {analyzing ? "Synthesizing..." : "Initiate D-Scan"}
          </button>
        </div>
      </div>

      {perfData ? (
        <div className="space-y-10">
          <div className="grid grid-cols-1 sm:grid-cols-3 gap-6">
            {[
              { label: 'Global Reach Index', val: perfData.reach, trend: '↑ 14%' },
              { label: 'Engagement Capacity', val: perfData.engagement, trend: 'Optimal' },
              { label: 'Brand Valuation', val: perfData.valuation, trend: 'Peak Performance' }
            ].map((kpi, idx) => (
              <div key={idx} className="bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-sm flex flex-col justify-between h-44 hover:shadow-xl transition-all">
                <span className="text-[10px] font-bold text-slate-400 uppercase tracking-[0.2em]">{kpi.label}</span>
                <p className="text-4xl font-bold text-slate-900 tracking-tighter">{kpi.val}</p>
                <div className="text-[9px] font-bold px-3 py-1.5 rounded-full w-fit bg-slate-50 text-slate-700">{kpi.trend}</div>
              </div>
            ))}
          </div>

          <div className="grid grid-cols-1 lg:grid-cols-12 gap-10">
            <div className="lg:col-span-8">
              <div className="bg-white border border-slate-100 rounded-[3.5rem] p-12 shadow-sm">
                <h3 className="text-3xl font-bold text-slate-900 serif italic mb-10 border-b pb-8">Intelligence Synthesis</h3>
                <div className="prose prose-slate max-w-none text-slate-700 font-light italic text-lg whitespace-pre-wrap">{insight}</div>

                {sources.length > 0 && (
                  <div className="mt-8 pt-8 border-t border-slate-100">
                    <h4 className="text-[10px] font-bold text-slate-400 uppercase tracking-[0.2em] mb-4 italic">Verification Sources</h4>
                    <div className="flex flex-wrap gap-3">
                      {sources.map((chunk: any, i: number) => (
                        chunk.web && (
                          <a 
                            key={i} 
                            href={chunk.web.uri} 
                            target="_blank" 
                            rel="noopener noreferrer"
                            className="text-[10px] font-bold text-amber-700 bg-amber-50 px-3 py-1.5 rounded-full hover:bg-amber-100 transition-colors flex items-center gap-2 border border-amber-100 shadow-sm"
                          >
                            {chunk.web.title || 'Source'} <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M10 6H6a2 2 0 00-2 2v10a2 2 0 002 2h10a2 2 0 002-2v-4M14 4h6m0 0v6m0-6L10 14" /></svg>
                          </a>
                        )
                      ))}
                    </div>
                  </div>
                )}
              </div>
            </div>

            <div className="lg:col-span-4">
               <div className="bg-white border border-slate-100 rounded-[3.5rem] p-12 shadow-sm h-full">
                  <h3 className="text-2xl font-bold text-slate-900 serif italic mb-16">Global Velocity</h3>
                  <div className="h-72 flex items-end gap-4 px-2">
                    {perfData.velocity.map((item, i) => (
                      <div key={i} className="flex-1 flex flex-col items-center">
                        <div className={`w-full rounded-t-lg transition-all duration-1000 ${item.value === 100 ? 'bg-amber-600' : 'bg-slate-100'}`} style={{ height: `${item.value * 2.5}px` }} />
                        <span className="text-[9px] font-bold text-slate-400 uppercase tracking-widest mt-4">{days[i]}</span>
                      </div>
                    ))}
                  </div>
               </div>
            </div>
          </div>
        </div>
      ) : (
        <div className="py-48 flex flex-col items-center justify-center text-center opacity-40">
           <svg className="w-24 h-24 text-slate-200 mb-8" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="1" d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" /></svg>
           <h3 className="text-4xl font-bold text-slate-900 serif italic tracking-tight">Intelligence Engine Active</h3>
           <p className="text-[10px] text-slate-400 font-bold uppercase tracking-[0.4em] mt-4 italic">Awaiting D-Scan synchronization parameters.</p>
        </div>
      )}
    </div>
  );
};

export default Dashboard;
