import React, { useState, useRef, useEffect } from 'react';
import { Track } from '../types';

interface MusicBarProps {
  track: Track;
}

const MusicBar: React.FC<MusicBarProps> = ({ track }) => {
  const [isPlaying, setIsPlaying] = useState(false);
  const audioRef = useRef<HTMLAudioElement | null>(null);

  // Synchronize playback with track changes initiated by the user
  useEffect(() => {
    if (audioRef.current && track.id !== 'default') {
      audioRef.current.load();
      const playPromise = audioRef.current.play();

      if (playPromise !== undefined) {
        playPromise.then(() => {
          setIsPlaying(true);
        }).catch(error => {
          console.warn("Autoplay policy restriction. Direct user interaction required to resume.", error);
          setIsPlaying(false);
        });
      }
    }
  }, [track]);

  const togglePlay = () => {
    if (audioRef.current) {
      if (isPlaying) {
        audioRef.current.pause();
        setIsPlaying(false);
      } else {
        audioRef.current.play().then(() => {
          setIsPlaying(true);
        }).catch(e => {
           alert("Platform Audio Activation: Please click anywhere on the interface to initialize the sound engine.");
        });
      }
    }
  };

  return (
    <div className="fixed bottom-0 left-0 right-0 h-28 bg-slate-950/98 backdrop-blur-3xl border-t border-slate-800 px-12 flex items-center justify-between z-[100] shadow-[0_-30px_70px_rgba(0,0,0,0.7)]">
      <audio 
        ref={audioRef} 
        src={track.url} 
        loop 
        onPlay={() => setIsPlaying(true)} 
        onPause={() => setIsPlaying(false)} 
      />

      {/* Track Identity Section */}
      <div className="flex items-center space-x-8 w-1/3">
        <div className="w-20 h-20 bg-slate-900 rounded-[1.5rem] flex items-center justify-center border border-slate-800 shadow-2xl overflow-hidden relative group">
           <img src={track.cover} alt="Cover" className="w-full h-full object-cover opacity-70 group-hover:opacity-100 transition-all duration-700" />
           <div className={`absolute inset-0 bg-amber-500/10 transition-opacity duration-700 ${isPlaying ? 'opacity-100' : 'opacity-0'}`}></div>
           {isPlaying && (
             <div className="absolute bottom-2 right-2 flex gap-1 items-end h-6 px-1">
                <div className="w-1 h-full bg-amber-500 animate-bounce rounded-full"></div>
                <div className="w-1 h-3/4 bg-amber-500 animate-bounce [animation-delay:0.2s] rounded-full"></div>
                <div className="w-1 h-1/2 bg-amber-500 animate-bounce [animation-delay:0.4s] rounded-full"></div>
             </div>
           )}
        </div>
        <div className="hidden sm:block overflow-hidden">
          <p className="text-base font-bold text-white uppercase tracking-[0.25em] truncate italic">{track.title}</p>
          <div className="flex items-center gap-3 mt-2">
             <span className="text-xs text-slate-500 font-bold uppercase tracking-[0.2em]">{track.artist}</span>
             <span className="text-[9px] bg-slate-900 text-amber-500 px-2 py-0.5 rounded-full font-bold border border-amber-900/50">LOSSLESS • 432Hz</span>
          </div>
        </div>
      </div>

      {/* Playback Controls & Timeline */}
      <div className="flex flex-col items-center w-1/3 gap-4">
        <div className="flex items-center gap-10">
           <button className="text-slate-600 hover:text-white transition-all hover:scale-125 active:scale-90">
              <svg className="w-6 h-6" fill="currentColor" viewBox="0 0 24 24"><path d="M6 6h2v12H6zm3.5 6l8.5 6V6z"/></svg>
           </button>
           <button 
            onClick={togglePlay}
            className="w-16 h-16 rounded-full bg-white flex items-center justify-center text-slate-950 hover:bg-amber-600 hover:text-white transition-all shadow-[0_0_50px_rgba(255,255,255,0.15)] active:scale-90 hover:scale-110"
          >
            {isPlaying ? (
              <svg className="w-10 h-10" fill="currentColor" viewBox="0 0 24 24"><path d="M6 19h4V5H6v14zm8-14v14h4V5h-4z"/></svg>
            ) : (
              <svg className="w-10 h-10 ml-1.5" fill="currentColor" viewBox="0 0 24 24"><path d="M8 5v14l11-7z"/></svg>
            )}
          </button>
           <button className="text-slate-600 hover:text-white transition-all hover:scale-125 active:scale-90">
              <svg className="w-6 h-6" fill="currentColor" viewBox="0 0 24 24"><path d="M16 6h2v12h-2zm-10.5 0v12l8.5-6z"/></svg>
           </button>
        </div>
        <div className="w-full max-w-lg flex items-center gap-6">
           <span className="text-[10px] text-slate-700 font-mono font-bold tracking-widest tabular-nums">0:00</span>
           <div className="flex-1 h-2 bg-slate-900 rounded-full relative overflow-hidden group cursor-pointer shadow-inner border border-slate-800">
             <div className={`absolute left-0 top-0 bottom-0 bg-amber-600 transition-all duration-1000 ${isPlaying ? 'w-1/2' : 'w-0'}`}></div>
             <div className="absolute top-0 bottom-0 w-1 bg-white opacity-0 group-hover:opacity-100 transition-opacity left-1/2"></div>
           </div>
           <span className="text-[10px] text-slate-700 font-mono font-bold tracking-widest tabular-nums">3:42</span>
        </div>
      </div>

      {/* Secondary Controls */}
