           <svg className="w-5 h-5 text-slate-600 group-hover:text-slate-300 transition-colors" fill="currentColor" viewBox="0 0 24 24"><path d="M3 9v6h4l5 5V4L7 9H3zm13.5 3c0-1.77-1.02-3.29-2.5-4.03v8.05c1.48-.73 2.5-2.25 2.5-4.02z"/></svg>
           <div className="w-28 h-1.5 bg-slate-900 rounded-full relative shadow-inner border border-slate-800">
              <div className="absolute inset-0 w-3/4 h-full bg-slate-600 rounded-full"></div>
           </div>
        </div>
        <div className="p-4 bg-slate-900 rounded-[1.25rem] border border-slate-800 hover:bg-slate-800 hover:border-amber-900 transition-all cursor-pointer group shadow-2xl active:scale-95">
           <svg className="w-6 h-6 text-slate-500 group-hover:text-amber-500 transition-colors" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z"/></svg>
        </div>
      </div>
    </div>
  );
};

