export const generateNewsletterContent = async (config: GenerationConfig) => {
  // Initialize right before making the API call as per best practices
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const prompt = `
    Generate a professional and engaging newsletter for 'Seed to Paradise', a boutique luxury botanical and wellness brand.

    Topic: ${config.topic}
    Tone: ${config.tone}
    Target Audience: ${config.audienceType}
    Include Special Offer: ${config.includeOffer ? 'Yes' : 'No'}

    The content MUST be personalized with placeholders like [Name].

    Structure:
    1. A catchy Subject Line.
    2. A warm personalized greeting.
    3. An introductory hook.
    4. Main body paragraphs about the topic.
    5. A call to action.
    6. A sign-off from "The Seed to Paradise Team".

    COMPLIANCE REQUIREMENTS:
    The output must strictly follow CAN-SPAM and CASL regulations. Do NOT include the unsubscribe footer in the main content; I will append it separately, but ensure the tone is suitable for an official advertisement.
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        temperature: 0.7,
        topP: 0.9,
      }
    });

    return response.text || "";
  } catch (error) {
    console.error("Error generating content:", error);
    throw error;
  }
};
