           <button className="text-slate-600 hover:text-white transition-all hover:scale-110 active:scale-90">
              <svg className="w-5 h-5" fill="currentColor" viewBox="0 0 24 24"><path d="M6 6h2v12H6zm3.5 6l8.5 6V6z"/></svg>
