                e.stopPropagation(); 
                if(confirm(`Are you sure you want to permanently delete "${item.label}"? This action cannot be reversed.`)) {
                  onDeleteMedia(item.id);
                }
              }}
              className="absolute top-4 right-4 z-20 w-10 h-10 bg-white/95 backdrop-blur-md rounded-full flex items-center justify-center text-slate-400 hover:text-rose-600 hover:bg-rose-50 hover:shadow-xl transition-all border border-slate-100 opacity-60 group-hover:opacity-100"
              title="Delete Asset"
            >
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
              </svg>
            </button>

            <div 
              className={`aspect-video bg-slate-950 relative flex items-center justify-center overflow-hidden ${item.type !== 'audio' ? 'cursor-zoom-in' : ''}`}
              onClick={() => item.type !== 'audio' && setViewerItem(item)}
            >
              {item.type === 'video' ? (
                <video src={item.url} className="w-full h-full object-cover opacity-60 group-hover:opacity-100 transition-opacity" muted loop autoPlay />
              ) : item.type === 'image' ? (
                <img src={item.url} className="w-full h-full object-cover opacity-80 group-hover:opacity-100 transition-opacity" alt={item.label} />
              ) : (
                <div className="text-amber-500 bg-amber-500/10 p-10 rounded-full border border-amber-500/20 shadow-inner">
                  <svg className="w-12 h-12" fill="currentColor" viewBox="0 0 20 20"><path d="M18 3a1 1 0 00-1.196-.98l-10 2A1 1 0 006 3v11H4a2 2 0 00-2 2v2a2 2 0 002 2h2a2 2 0 002-2V7.4l9-1.8V17a2 2 0 00-2 2v2a2 2 0 002 2h2a2 2 0 002-2V3z" /></svg>
                </div>
              )}
              {item.type !== 'audio' && (
                <div className="absolute inset-0 bg-slate-950/20 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center pointer-events-none">
                  <span className="text-[10px] text-white font-bold uppercase tracking-widest bg-slate-950/80 px-6 py-3 rounded-full backdrop-blur-md border border-white/10">Strategic Inspection</span>
                </div>
              )}
            </div>

            <div className="p-10 flex-1 flex flex-col justify-between">
              <div>
                {editingId === item.id ? (
                  <div className="flex gap-2">
                    <input 
                      autoFocus
                      className="bg-slate-50 border border-amber-500 rounded-xl px-4 py-2 w-full text-lg font-bold serif italic outline-none"
                      value={tempLabel}
                      onChange={(e) => setTempLabel(e.target.value)}
                      onKeyDown={(e) => {
                        if (e.key === 'Enter') { onRenameMedia(item.id, tempLabel); setEditingId(null); }
                        if (e.key === 'Escape') setEditingId(null);
                      }}
                    />
                    <button 
                      onClick={() => { onRenameMedia(item.id, tempLabel); setEditingId(null); }}
                      className="bg-slate-950 text-white p-2 rounded-xl text-xs font-bold px-4 hover:bg-amber-700 transition-colors"
                    >
                      OK
                    </button>
                  </div>
                ) : (
                  <div className="flex justify-between items-start group/name">
                    <h4 className="font-bold text-slate-900 text-3xl serif italic tracking-tight truncate capitalize">{item.label}</h4>
                    <button 
                      onClick={() => { setEditingId(item.id); setTempLabel(item.label); }}
                      className="opacity-0 group-hover/name:opacity-100 text-slate-400 hover:text-amber-700 transition-all p-1"
                    >
                      <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M15.232 5.232l3.536 3.536m-2.036-5.036a2.5 2.5 0 113.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z" /></svg>
                    </button>
                  </div>
                )}
                <p className="text-[10px] text-slate-400 uppercase font-bold tracking-[0.2em] italic mt-2">Active Studio Session Node</p>
              </div>
            </div>
          </div>
        ))}
      </div>

      {/* Fullscreen Media Viewer */}
      {viewerItem && (viewerItem.type === 'video' || viewerItem.type === 'image') && (
        <div className="fixed inset-0 z-[2000] bg-slate-950 flex flex-col animate-fadeIn select-none overflow-hidden">
          <div className="absolute top-0 left-0 right-0 p-8 flex justify-between items-center z-[2010] bg-gradient-to-b from-slate-950/90 to-transparent">
            <div>
              <p className="text-[10px] font-bold text-amber-500 uppercase tracking-[0.4em] mb-2 italic">Strategic Asset View</p>
              <h3 className="text-4xl font-bold text-white serif italic tracking-tighter capitalize drop-shadow-lg">{viewerItem.label}</h3>
            </div>
            <div className="flex items-center gap-4">
              <button 
                onClick={toggleFullscreen}
                className="p-4 bg-white/10 hover:bg-white/20 text-white rounded-2xl border border-white/10 transition-all backdrop-blur-md"
                title="Toggle Fullscreen"
              >
                <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 8V4m0 0h4M4 4l5 5m11-1V4m0 0h-4m4 0l-5 5M4 16v4m0 0h4m-4 0l5-5m11 5l-5-5m5 5v-4m0 4h-4" />
                </svg>
              </button>
              <button 
                onClick={() => setViewerItem(null)}
                className="p-4 bg-white text-slate-950 rounded-2xl hover:bg-amber-600 hover:text-white transition-all shadow-2xl"
              >
                <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12" />
                </svg>
              </button>
            </div>
          </div>

          <div 
            ref={viewerContainerRef}
            className="flex-1 flex items-center justify-center bg-black"
          >
            {viewerItem.type === 'video' ? (
              <video 
                src={viewerItem.url} 
                className="max-w-full max-h-full w-full h-full object-contain" 
                controls 
                autoPlay 
              />
            ) : (
              <img 
                src={viewerItem.url} 
                className="max-w-full max-h-full w-full h-full object-contain" 
                alt={viewerItem.label} 
              />
            )}
          </div>
        </div>
      )}
    </div>
  );
};

