import React, { useRef, useState, useEffect } from 'react';
import { MediaItem } from '../types';

interface SocialAssetsProps {
  mediaItems: MediaItem[];
  onAddMedia: (file: File, type: 'video' | 'image' | 'audio') => void;
  onRenameMedia: (id: string, newLabel: string) => void;
  onDeleteMedia: (id: string) => void;
}

const SocialAssets: React.FC<SocialAssetsProps> = ({ mediaItems, onAddMedia, onRenameMedia, onDeleteMedia }) => {
  const fileInputRef = useRef<HTMLInputElement>(null);
  const viewerContainerRef = useRef<HTMLDivElement>(null);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [tempLabel, setTempLabel] = useState("");
  const [viewerItem, setViewerItem] = useState<MediaItem | null>(null);

  const handleFile = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const type = file.type.startsWith('video') ? 'video' : file.type.startsWith('audio') ? 'audio' : 'image';
      onAddMedia(file, type);
    }
  };

  const toggleFullscreen = () => {
    if (!document.fullscreenElement) {
      viewerContainerRef.current?.requestFullscreen().catch(err => {
        console.error(`Error enabling fullscreen: ${err.message}`);
      });
    } else {
      document.exitFullscreen();
    }
  };

  useEffect(() => {
    const handleEsc = (e: KeyboardEvent) => {
      if (e.key === 'Escape') setViewerItem(null);
    };
    window.addEventListener('keydown', handleEsc);
    return () => window.removeEventListener('keydown', handleEsc);
  }, []);

  return (
    <div className="space-y-12 py-8 animate-fadeIn relative">
      <header className="flex justify-between items-end border-b border-slate-200 pb-10">
        <div>
          <h2 className="text-5xl font-bold text-slate-900 serif italic tracking-tighter">Production Studio</h2>
          <p className="text-slate-400 mt-2 font-bold uppercase text-[11px] tracking-[0.3em]">High-Resolution Asset Stream</p>
        </div>
        <input type="file" ref={fileInputRef} className="hidden" onChange={handleFile} />
        <button 
          onClick={() => fileInputRef.current?.click()}
          className="px-10 py-5 bg-slate-950 text-white rounded-[1.5rem] text-[11px] font-bold uppercase tracking-[0.2em] shadow-2xl hover:bg-amber-700 transition-all border border-slate-800"
        >
          Import Production Node
        </button>
      </header>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-10">
        {mediaItems.length === 0 && (
          <div 
            onClick={() => fileInputRef.current?.click()}
            className="col-span-full border-4 border-dashed border-slate-100 rounded-[3rem] py-48 text-center cursor-pointer hover:border-amber-200 hover:bg-amber-50/20 transition-all"
          >
            <p className="text-2xl font-bold text-slate-300 serif italic">No Production Assets Detected</p>
            <p className="text-[10px] text-slate-400 mt-4 uppercase font-bold tracking-widest">Awaiting local asset synchronization.</p>
          </div>
        )}

        {mediaItems.map((item) => (
          <div 
            key={item.id} 
            className="bg-white rounded-[2.5rem] border border-slate-100 shadow-sm overflow-hidden group hover:shadow-2xl transition-all flex flex-col relative"
          >
            {/* Visual Preview Area */}
            <div 
              className={`aspect-video bg-slate-950 relative flex items-center justify-center overflow-hidden ${item.type !== 'audio' ? 'cursor-zoom-in' : ''}`}
              onClick={() => item.type !== 'audio' && setViewerItem(item)}
            >
              {item.type === 'video' ? (
                <video src={item.url} className="w-full h-full object-cover opacity-60 group-hover:opacity-100 transition-opacity" muted loop autoPlay />
              ) : item.type === 'image' ? (
                <img src={item.url} className="w-full h-full object-cover opacity-80 group-hover:opacity-100 transition-opacity" alt={item.label} />
              ) : (
                <div className="text-amber-500 bg-amber-500/10 p-10 rounded-full border border-amber-500/20 shadow-inner">
                  <svg className="w-12 h-12" fill="currentColor" viewBox="0 0 20 20"><path d="M18 3a1 1 0 00-1.196-.98l-10 2A1 1 0 006 3v11H4a2 2 0 00-2 2v2a2 2 0 002 2h2a2 2 0 002-2V7.4l9-1.8V17a2 2 0 00-2 2v2a2 2 0 002 2h2a2 2 0 002-2V3z" /></svg>
                </div>
              )}
              {item.type !== 'audio' && (
                <div className="absolute inset-0 bg-slate-950/20 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center pointer-events-none">
                  <span className="text-[10px] text-white font-bold uppercase tracking-widest bg-slate-950/80 px-6 py-3 rounded-full backdrop-blur-md border border-white/10">Expand Vision</span>
                </div>
              )}
            </div>

            {/* Asset Details & Actions */}
            <div className="p-8 flex-1 flex flex-col justify-between space-y-4">
              {editingId === item.id ? (
                <div className="flex flex-col gap-3">
                  <input 
                    autoFocus
                    className="bg-slate-50 border-2 border-amber-500 rounded-xl px-5 py-3 w-full text-lg font-bold serif italic outline-none"
                    value={tempLabel}
                    onChange={(e) => setTempLabel(e.target.value)}
                    onKeyDown={(e) => {
                      if (e.key === 'Enter') { onRenameMedia(item.id, tempLabel); setEditingId(null); }
                      if (e.key === 'Escape') setEditingId(null);
                    }}
                  />
                  <div className="flex gap-2">
                    <button 
                      onClick={() => { onRenameMedia(item.id, tempLabel); setEditingId(null); }}
                      className="flex-1 bg-slate-900 text-white py-2 rounded-xl text-[10px] font-bold uppercase tracking-widest hover:bg-amber-700 transition-colors"
                    >
                      Commit Changes
                    </button>
                    <button 
                      onClick={() => setEditingId(null)}
                      className="px-4 py-2 bg-slate-100 text-slate-500 rounded-xl text-[10px] font-bold uppercase hover:bg-slate-200 transition-colors"
                    >
                      Cancel
                    </button>
                  </div>
                </div>
              ) : (
                <div className="space-y-6">
                  <div className="flex justify-between items-start gap-4">
                    <h4 className="font-bold text-slate-900 text-2xl serif italic tracking-tight truncate capitalize">{item.label}</h4>
                    <span className="text-[9px] bg-slate-100 text-slate-500 px-3 py-1 rounded-full font-bold uppercase tracking-widest border border-slate-200">{item.type}</span>
                  </div>

                  <div className="flex items-center justify-between pt-4 border-t border-slate-50">
                    <div className="flex gap-4">
                      {/* Explicit Rename Button */}
                      <button 
                        onClick={() => { setEditingId(item.id); setTempLabel(item.label); }}
                        className="flex items-center gap-2 text-[10px] font-bold text-slate-400 hover:text-amber-700 transition-all uppercase tracking-widest group/btn"
                      >
                        <svg className="w-4 h-4 transition-transform group-hover/btn:scale-110" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15.232 5.232l3.536 3.536m-2.036-5.036a2.5 2.5 0 113.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z" /></svg>
                        <span>Rename</span>
                      </button>

                      {/* Explicit DELETE Button */}
                      <button 
                        onClick={(e) => { 
                          e.stopPropagation(); 
                          if(confirm(`WARNING: Permanent erasure of asset node "${item.label}". Proceed?`)) {
                            onDeleteMedia(item.id);
                          }
                        }}
                        className="flex items-center gap-2 text-[10px] font-bold text-slate-400 hover:text-rose-600 transition-all uppercase tracking-widest group/del"
                      >
                        <svg className="w-4 h-4 transition-transform group-hover/del:scale-110" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
                        <span>Delete</span>
                      </button>
                    </div>

                    <p className="text-[8px] text-slate-300 font-bold uppercase tracking-[0.2em] italic">Vault Node Active</p>
                  </div>
