                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                onKeyPress={(e) => e.key === 'Enter' && performInternetAnalysis()}
              />
          </div>
          <button onClick={performInternetAnalysis} className="w-full md:w-80 bg-slate-100 text-slate-950 py-5 rounded-2xl font-bold uppercase tracking-widest text-[11px] hover:bg-white transition-all shadow-2xl active:scale-95">
            {analyzing ? "Synthesizing..." : "Initiate D-Scan"}
          </button>
        </div>
      </div>

      {perfData ? (
        <div className="space-y-10">
          <div className="grid grid-cols-1 sm:grid-cols-3 gap-6">
            {[
              { label: 'Global Reach Index', val: perfData.reach, trend: '↑ 14%' },
              { label: 'Engagement Capacity', val: perfData.engagement, trend: 'Optimal' },
              { label: 'Brand Valuation', val: perfData.valuation, trend: 'Peak Performance' }
