import React, { useState, useCallback } from 'react';
import TopNav from './components/TopNav';
import Dashboard from './components/Dashboard';
import BusinessTools from './components/BusinessTools';
import SocialAssets from './components/SocialAssets';
import MusicBar from './components/MusicBar';
import AccessibilityArrow from './components/AccessibilityArrow';
import { Module, NewsletterCampaign, Subscriber, Track, MediaItem } from './types';

const App: React.FC = () => {
  const [activeModule, setActiveModule] = useState<Module>(Module.DASHBOARD);
  const [mediaItems, setMediaItems] = useState<MediaItem[]>([]);
  const [campaigns, setCampaigns] = useState<NewsletterCampaign[]>([]);
  const [subscribers, setSubscribers] = useState<Subscriber[]>([
    { id: '1', name: 'Julian Reed', email: 'j.reed@spectro.co', status: 'active', subscribedAt: '2024-01-05' },
    { id: '2', name: 'Elena Thorne', email: 'elena@blueprint.me', status: 'active', subscribedAt: '2024-02-14' },
    { id: '3', name: 'Marcus Vane', email: 'm.vane@architecture.org', status: 'active', subscribedAt: '2024-03-20' },
  ]);
  const [currentTrack, setCurrentTrack] = useState<Track>({
    id: 'default',
    title: 'Blueprint Alpha Resonance',
    artist: 'SpectroModel Studio',
    url: 'https://cdn.pixabay.com/audio/2022/02/10/audio_f3299c80f4.mp3',
    cover: 'https://images.unsplash.com/photo-1503387762-592dea58ef23?w=200'
  });

  const addMediaToStudio = useCallback(async (file: File, type: 'video' | 'image' | 'audio') => {
    const id = Math.random().toString(36).substr(2, 9);
    const label = file.name.split('.')[0].replace(/[-_]/g, ' ');
    const blobUrl = URL.createObjectURL(file);

    const newItem: MediaItem = {
      id,
      type,
      label,
      fileName: file.name,
      url: blobUrl
    };

    setMediaItems(prev => [newItem, ...prev]);
  }, []);

  const renameMediaInStudio = useCallback((id: string, newLabel: string) => {
    setMediaItems(prev => prev.map(item => 
      item.id === id ? { ...item, label: newLabel } : item
    ));
  }, []);

  const deleteMediaFromStudio = useCallback((id: string) => {
    setMediaItems(prev => {
      const item = prev.find(i => i.id === id);
      if (item && item.url.startsWith('blob:')) {
        URL.revokeObjectURL(item.url);
      }
      return prev.filter(i => i.id !== id);
    });
  }, []);

  const deleteSubscriber = useCallback((id: string) => {
    setSubscribers(prev => prev.filter(s => s.id !== id));
  }, []);

  const handleSaveCampaign = (data: Partial<NewsletterCampaign>) => {
    const newCamp: NewsletterCampaign = {
      id: Math.random().toString(36).substr(2, 9),
      title: data.title || 'Untitled',
      subject: data.subject || '',
      content: data.content || '',
      createdAt: new Date().toISOString().split('T')[0],
      status: 'draft',
      recipientsCount: 0
    };
    setCampaigns([newCamp, ...campaigns]);
    setActiveModule(Module.DASHBOARD);
  };

  const renderModule = () => {
    switch (activeModule) {
      case Module.DASHBOARD:
        return <Dashboard campaigns={campaigns} onPlayTrack={setCurrentTrack} />;
      case Module.NEWSLETTER:
        return <BusinessTools campaigns={campaigns} subscribers={subscribers} onSaveCampaign={handleSaveCampaign} onDeleteSubscriber={deleteSubscriber} />;
      case Module.ASSETS:
        return <SocialAssets 
          mediaItems={mediaItems} 
          onAddMedia={addMediaToStudio} 
          onRenameMedia={renameMediaInStudio} 
          onDeleteMedia={deleteMediaFromStudio}
        />;
      case Module.SETTINGS:
        return (
          <div className="py-20 text-center space-y-6">
             <h2 className="text-4xl font-bold serif italic text-slate-900 tracking-tight">Platform Control Center</h2>
             <p className="text-slate-400 font-bold uppercase text-[11px] tracking-[0.4em]">Global Brand Orchestration</p>
             <div className="max-w-xl mx-auto bg-white p-12 rounded-[3.5rem] border border-slate-100 shadow-2xl text-left">
                <div className="space-y-8">
                  <div>
                    <label className="text-[10px] font-bold uppercase tracking-[0.3em] text-slate-400">Environment Node</label>
                    <p className="text-xl font-bold text-slate-900 border-b border-slate-100 pb-3 serif italic">Production Engines Active</p>
                  </div>
                  <div>
                    <label className="text-[10px] font-bold uppercase tracking-[0.3em] text-slate-400">Current Version</label>
                    <p className="text-xl font-bold text-amber-700 border-b border-slate-100 pb-3 serif italic">SpectroModel Studio v5.1 (Studio Integrated)</p>
                  </div>
                </div>
             </div>
          </div>
        );
      default:
        return <Dashboard campaigns={campaigns} onPlayTrack={setCurrentTrack} />;
    }
  };

  return (
    <div className="min-h-screen bg-[#fcfbf7] pb-24 font-sans selection:bg-amber-100 selection:text-amber-900">
      <TopNav activeModule={activeModule} setModule={setActiveModule} />
      <main className="pt-24 px-8 md:px-16 max-w-7xl mx-auto">
        {renderModule()}
      </main>
      <AccessibilityArrow />
      <MusicBar track={currentTrack} />
    </div>
  );
};

export default App;

import React, { useRef, useState, useEffect } from 'react';
import { MediaItem } from '../types';

interface SocialAssetsProps {
  mediaItems: MediaItem[];
  onAddMedia: (file: File, type: 'video' | 'image' | 'audio') => void;
  onRenameMedia: (id: string, newLabel: string) => void;
  onDeleteMedia: (id: string) => void;
}

const SocialAssets: React.FC<SocialAssetsProps> = ({ mediaItems, onAddMedia, onRenameMedia, onDeleteMedia }) => {
  const videoInputRef = useRef<HTMLInputElement>(null);
  const imageInputRef = useRef<HTMLInputElement>(null);
  const audioInputRef = useRef<HTMLInputElement>(null);
  const modalMediaRef = useRef<HTMLDivElement>(null);

  const [viewingAsset, setViewingAsset] = useState<MediaItem | null>(null);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [tempLabel, setTempLabel] = useState("");

  useEffect(() => {
    const handleEsc = (e: KeyboardEvent) => {
      if (e.key === 'Escape') setViewingAsset(null);
    };
    window.addEventListener('keydown', handleEsc);
    return () => window.removeEventListener('keydown', handleEsc);
  }, []);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>, type: 'video' | 'image' | 'audio') => {
    const file = e.target.files?.[0];
    if (file) {
      onAddMedia(file, type);
      e.target.value = ''; 
    }
  };

  const startEditing = (e: React.MouseEvent, item: MediaItem) => {
    e.stopPropagation();
    setEditingId(item.id);
    setTempLabel(item.label);
  };

  const saveRename = (e: React.FormEvent | React.MouseEvent, id: string) => {
    e.preventDefault();
    e.stopPropagation();
    if (tempLabel.trim()) {
      onRenameMedia(id, tempLabel.trim());
    }
    setEditingId(null);
  };

  const cancelRename = (e: React.MouseEvent) => {
    e.stopPropagation();
    setEditingId(null);
  };

  const handleDelete = (e: React.MouseEvent, item: MediaItem) => {
    e.stopPropagation();
    const confirmed = window.confirm(`Permanently remove asset "${item.label}" from the production vault?`);
    if (confirmed) {
      onDeleteMedia(item.id);
    }
  };

  const toggleBrowserFullscreen = (e: React.MouseEvent) => {
    e.stopPropagation();
    if (!document.fullscreenElement) {
      modalMediaRef.current?.requestFullscreen().catch(err => {
        console.error(`Error enabling fullscreen: ${err.message}`);
      });
    } else {
      document.exitFullscreen();
    }
  };

  return (
    <div className="space-y-12 animate-fadeIn py-8 relative">
      <header className="flex flex-col md:flex-row justify-between items-start md:items-end border-b border-slate-200 pb-10 gap-6">
        <div>
          <h2 className="text-5xl font-bold text-slate-900 serif italic tracking-tighter">Media Production Studio</h2>
          <p className="text-slate-500 mt-2 font-bold uppercase text-[11px] tracking-[0.3em]">Session-Based Asset Stream</p>
        </div>

        <input type="file" ref={videoInputRef} accept="video/*" className="hidden" onChange={(e) => handleFileChange(e, 'video')} />
        <input type="file" ref={imageInputRef} accept="image/*" className="hidden" onChange={(e) => handleFileChange(e, 'image')} />
        <input type="file" ref={audioInputRef} accept="audio/*" className="hidden" onChange={(e) => handleFileChange(e, 'audio')} />

        <div className="flex gap-4 w-full md:w-auto">
          <button 
            onClick={() => imageInputRef.current?.click()}
            className="flex-1 md:flex-none px-8 py-4 bg-slate-950 text-white rounded-2xl text-[10px] font-bold uppercase tracking-widest hover:bg-amber-700 transition-all flex items-center justify-center gap-3 shadow-2xl border border-slate-800"
          >
            Import Asset
          </button>
        </div>
      </header>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-10">
        {mediaItems.map((item) => (
          <div 
            key={item.id} 
            className="bg-white rounded-[3rem] border border-slate-100 shadow-sm overflow-hidden group hover:shadow-2xl transition-all flex flex-col relative"
          >
            {/* Floating Actions */}
            <div className="absolute top-6 right-6 z-[100] flex flex-col gap-3 pointer-events-auto">
              <button 
                type="button"
                onClick={(e) => startEditing(e, item)}
                className="w-12 h-12 bg-slate-950 hover:bg-amber-600 text-white rounded-full flex items-center justify-center transition-all backdrop-blur-md border border-white/20 shadow-2xl opacity-0 group-hover:opacity-100 transform translate-y-2 group-hover:translate-y-0 active:scale-90"
                title="Rename Asset"
              >
                <svg className="w-5 h-5 pointer-events-none" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M15.232 5.232l3.536 3.536m-2.036-5.036a2.5 2.5 0 113.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z" />
                </svg>
              </button>
              <button 
