                    ))}
                  </div>
                </div>
              )}
            </div>
          )}

          {/* Campaign Drafts Archive */}
          <div className="bg-white border border-slate-100 rounded-[3.5rem] p-12 shadow-sm">
            <h3 className="text-3xl font-bold text-slate-900 serif italic mb-8 border-b border-slate-50 pb-6">Recent Campaigns</h3>
            {campaigns.length > 0 ? (
              <div className="space-y-4">
                {campaigns.map((camp) => (
                  <div key={camp.id} className="group flex items-center justify-between p-6 bg-slate-50 hover:bg-white border border-transparent hover:border-slate-100 rounded-[2rem] transition-all">
                    <div className="flex-1 min-w-0">
