export default Dashboard;

import React, { useRef, useState, useEffect } from 'react';
import { MediaItem } from '../types';

interface SocialAssetsProps {
  mediaItems: MediaItem[];
  onAddMedia: (file: File, type: 'video' | 'image' | 'audio') => void;
  onRenameMedia: (id: string, newLabel: string) => void;
  onDeleteMedia: (id: string) => void;
}

const SocialAssets: React.FC<SocialAssetsProps> = ({ mediaItems, onAddMedia, onRenameMedia, onDeleteMedia }) => {
  const videoInputRef = useRef<HTMLInputElement>(null);
  const imageInputRef = useRef<HTMLInputElement>(null);
  const audioInputRef = useRef<HTMLInputElement>(null);
  const modalMediaRef = useRef<HTMLDivElement>(null);

  const [viewingAsset, setViewingAsset] = useState<MediaItem | null>(null);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [tempLabel, setTempLabel] = useState("");

  useEffect(() => {
    const handleEsc = (e: KeyboardEvent) => {
      if (e.key === 'Escape') setViewingAsset(null);
    };
    window.addEventListener('keydown', handleEsc);
    return () => window.removeEventListener('keydown', handleEsc);
  }, []);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>, type: 'video' | 'image' | 'audio') => {
    const file = e.target.files?.[0];
    if (file) {
      onAddMedia(file, type);
      e.target.value = ''; 
    }
  };

  const startEditing = (e: React.MouseEvent, item: MediaItem) => {
    e.stopPropagation();
    setEditingId(item.id);
    setTempLabel(item.label);
  };

  const saveRename = (e: React.FormEvent | React.MouseEvent, id: string) => {
    e.preventDefault();
    e.stopPropagation();
    if (tempLabel.trim()) {
      onRenameMedia(id, tempLabel.trim());
    }
    setEditingId(null);
  };

  const cancelRename = (e: React.MouseEvent) => {
    e.stopPropagation();
    setEditingId(null);
  };

  const handleDelete = (e: React.MouseEvent, item: MediaItem) => {
    e.stopPropagation();
    const confirmed = window.confirm(`Permanently remove asset "${item.label}" from the production vault?`);
    if (confirmed) {
      onDeleteMedia(item.id);
    }
  };

  const toggleBrowserFullscreen = (e: React.MouseEvent) => {
    e.stopPropagation();
    if (!document.fullscreenElement) {
      modalMediaRef.current?.requestFullscreen().catch(err => {
        console.error(`Error enabling fullscreen: ${err.message}`);
      });
    } else {
      document.exitFullscreen();
    }
  };

  return (
    <div className="space-y-12 animate-fadeIn py-8 relative">
      <header className="flex flex-col md:flex-row justify-between items-start md:items-end border-b border-slate-200 pb-10 gap-6">
        <div>
          <h2 className="text-5xl font-bold text-slate-900 serif italic tracking-tighter">Media Production Studio</h2>
          <p className="text-slate-500 mt-2 font-bold uppercase text-[11px] tracking-[0.3em]">Session-Based Asset Stream</p>
        </div>

        <input type="file" ref={videoInputRef} accept="video/*" className="hidden" onChange={(e) => handleFileChange(e, 'video')} />
        <input type="file" ref={imageInputRef} accept="image/*" className="hidden" onChange={(e) => handleFileChange(e, 'image')} />
        <input type="file" ref={audioInputRef} accept="audio/*" className="hidden" onChange={(e) => handleFileChange(e, 'audio')} />

        <div className="flex gap-4 w-full md:w-auto">
          <button 
            onClick={() => imageInputRef.current?.click()}
            className="flex-1 md:flex-none px-8 py-4 bg-slate-950 text-white rounded-2xl text-[10px] font-bold uppercase tracking-widest hover:bg-amber-700 transition-all flex items-center justify-center gap-3 shadow-2xl border border-slate-800"
          >
            Import Asset
          </button>
        </div>
      </header>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-10">
        {mediaItems.map((item) => (
          <div 
            key={item.id} 
            className="bg-white rounded-[3rem] border border-slate-100 shadow-sm overflow-hidden group hover:shadow-2xl transition-all flex flex-col relative"
          >
            {/* Floating Actions */}
            <div className="absolute top-6 right-6 z-[100] flex flex-col gap-3 pointer-events-auto">
              <button 
                type="button"
                onClick={(e) => startEditing(e, item)}
                className="w-12 h-12 bg-white/90 backdrop-blur text-slate-900 hover:bg-amber-600 hover:text-white rounded-full flex items-center justify-center transition-all border border-slate-100 shadow-xl opacity-0 group-hover:opacity-100 transform translate-y-2 group-hover:translate-y-0 active:scale-90"
                title="Rename Asset"
              >
                <svg className="w-5 h-5 pointer-events-none" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15.232 5.232l3.536 3.536m-2.036-5.036a2.5 2.5 0 113.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z" />
                </svg>
              </button>
              <button 
                type="button"
                onClick={(e) => handleDelete(e, item)}
                className="w-12 h-12 bg-white/90 backdrop-blur text-rose-600 hover:bg-rose-600 hover:text-white rounded-full flex items-center justify-center transition-all border border-slate-100 shadow-xl opacity-0 group-hover:opacity-100 transform translate-y-4 group-hover:translate-y-0 active:scale-90 delay-[50ms]"
                title="Purge Asset"
              >
                <svg className="w-5 h-5 pointer-events-none" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
                </svg>
              </button>
            </div>

            <div 
              className={`aspect-video bg-slate-950 relative flex items-center justify-center overflow-hidden ${item.type !== 'audio' ? 'cursor-pointer' : ''}`}
              onClick={() => item.type !== 'audio' && setViewingAsset(item)}
            >
              {item.type === 'video' ? (
                <>
                  <video src={item.url} className="w-full h-full object-cover opacity-60 group-hover:opacity-100 transition-opacity" />
                  <div className="absolute inset-0 bg-slate-950/30 group-hover:bg-transparent transition-colors flex items-center justify-center opacity-0 group-hover:opacity-100 pointer-events-none">
                     <span className="text-[10px] text-white font-bold uppercase tracking-[0.4em] bg-slate-950/80 px-8 py-4 rounded-full backdrop-blur-md border border-white/10">Strategic View</span>
                  </div>
                </>
              ) : item.type === 'image' ? (
                <>
                  <img src={item.url} className="w-full h-full object-cover opacity-80 group-hover:opacity-100 transition-opacity duration-1000" alt={item.label} />
                  <div className="absolute inset-0 bg-slate-950/20 group-hover:bg-transparent transition-colors flex items-center justify-center opacity-0 group-hover:opacity-100 pointer-events-none">
                     <span className="text-[10px] text-white font-bold uppercase tracking-[0.4em] bg-slate-950/80 px-8 py-4 rounded-full backdrop-blur-md border border-white/10">Inspection View</span>
                  </div>
                </>
              ) : (
                <div className="flex flex-col items-center gap-6 text-amber-500 w-full px-8">
                  <div className="w-20 h-20 rounded-full bg-amber-500/10 flex items-center justify-center border border-amber-500/20 shadow-inner">
                    <svg className="w-10 h-10" fill="currentColor" viewBox="0 0 20 20"><path d="M18 3a1 1 0 00-1.196-.98l-10 2A1 1 0 006 3v11H4a2 2 0 00-2 2v2a2 2 0 002 2h2a2 2 0 002-2V7.4l9-1.8V17a2 2 0 00-2 2v2a2 2 0 002 2h2a2 2 0 002-2V3z" /></svg>
                  </div>
                  <audio src={item.url} controls className="w-full h-10 accent-amber-600 relative z-10" onClick={(e) => e.stopPropagation()} />
                </div>
              )}
            </div>

            <div className="p-10 flex-1 flex flex-col justify-between">
              <div>
                {editingId === item.id ? (
                  <form 
                    onSubmit={(e) => saveRename(e, item.id)} 
                    className="flex items-center gap-2 mb-2 relative z-10"
                    onClick={(e) => e.stopPropagation()}
                  >
                    <input 
                      autoFocus
                      type="text"
                      className="flex-1 bg-slate-50 border border-amber-500 rounded-xl px-4 py-2 text-lg font-bold text-slate-900 serif italic outline-none focus:ring-4 focus:ring-amber-500/20"
                      value={tempLabel}
                      onChange={(e) => setTempLabel(e.target.value)}
                    />
                    <button type="submit" className="p-2 text-green-600 hover:text-green-800 bg-green-50 rounded-lg">
                      <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M5 13l4 4L19 7" /></svg>
                    </button>
                    <button onClick={cancelRename} className="p-2 text-rose-600 hover:text-rose-800 bg-rose-50 rounded-lg">
                      <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M6 18L18 6M6 6l12 12" /></svg>
                    </button>
                  </form>
                ) : (
                  <h4 className="font-bold text-slate-900 text-3xl serif italic tracking-tight mb-2 truncate capitalize">{item.label}</h4>
                )}
                <p className="text-[10px] text-slate-400 uppercase font-bold tracking-[0.2em] italic">{item.fileName || 'Asset Node'}</p>
              </div>
              <div className="mt-8 pt-8 border-t border-slate-50 flex justify-between items-center">
                 <div className="flex gap-2 items-center">
                    <div className="w-2 h-2 rounded-full bg-amber-500 shadow-sm"></div>
                    <span className="text-[9px] font-bold text-slate-400 uppercase tracking-widest">Active Studio Session</span>
                 </div>
              </div>
            </div>
          </div>
        ))}

        <div 
          onClick={() => imageInputRef.current?.click()}
          className="border-4 border-dashed border-slate-100 rounded-[3.5rem] flex flex-col items-center justify-center p-12 text-center group cursor-pointer hover:border-amber-400 hover:bg-amber-50/30 transition-all min-h-[450px]"
        >
           <div className="w-24 h-24 rounded-full bg-slate-50 flex items-center justify-center mb-8 group-hover:bg-amber-100 group-hover:scale-110 transition-all duration-500 shadow-inner">
              <svg className="w-12 h-12 text-slate-200 group-hover:text-amber-700 transition-colors" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="1" d="M12 4v16m8-8H4" /></svg>
           </div>
           <p className="text-2xl font-bold text-slate-300 group-hover:text-slate-900 serif italic transition-colors">Import Production Asset</p>
           <p className="text-[10px] text-slate-400 mt-4 uppercase font-bold tracking-widest">Session Retention Logic</p>
        </div>
      </div>

      {viewingAsset && (
        <div 
          className="fixed inset-0 z-[2000] bg-black flex flex-col animate-fadeIn select-none overflow-hidden"
          onClick={() => setViewingAsset(null)}
        >
           <div className="absolute top-0 left-0 right-0 p-10 flex justify-between items-center z-[2010] bg-gradient-to-b from-black/90 to-transparent">
              <div>
                 <span className="text-[10px] font-bold text-amber-500 uppercase tracking-[0.6em] mb-3 block italic drop-shadow-lg">Strategic Asset Inspection</span>
                 <h3 className="text-4xl md:text-6xl font-bold text-white serif italic tracking-tighter capitalize drop-shadow-2xl">{viewingAsset.label}</h3>
              </div>

              <div className="flex gap-6">
                 <button 
                   onClick={(e) => toggleBrowserFullscreen(e)}
                   className="w-16 h-16 bg-white/10 hover:bg-white/20 text-white rounded-2xl flex items-center justify-center transition-all shadow-2xl active:scale-90 border border-white/10 backdrop-blur-xl"
                   title="Browser Fullscreen"
                 >
                   <svg className="w-8 h-8 pointer-events-none" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 8V4m0 0h4M4 4l5 5m11-1V4m0 0h-4m4 0l-5 5M4 16v4m0 0h4m-4 0l5-5m11 5l-5-5m5 5v-4m0 4h-4" /></svg>
                 </button>
                 <button 
                   className="w-16 h-16 bg-white hover:bg-amber-600 text-black hover:text-white rounded-2xl flex items-center justify-center transition-all shadow-2xl active:scale-90 border border-white/10"
                   onClick={() => setViewingAsset(null)}
                 >
                    <svg className="w-10 h-10 pointer-events-none" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12" /></svg>
                 </button>
              </div>
           </div>

           <div 
             ref={modalMediaRef}
             className="w-full h-full flex items-center justify-center bg-black animate-zoomIn"
             onClick={(e) => e.stopPropagation()}
           >
              {viewingAsset.type === 'video' ? (
                <video 
                  src={viewingAsset.url} 
                  className="max-w-full max-h-full w-full h-full object-contain shadow-[0_0_100px_rgba(0,0,0,0.8)]" 
                  controls 
                  autoPlay 
                  playsInline
                />
              ) : (
                <img 
                  src={viewingAsset.url} 
                  className="max-w-full max-h-full w-full h-full object-contain select-none shadow-[0_0_100px_rgba(0,0,0,0.8)]" 
                  alt={viewingAsset.label} 
                />
              )}
           </div>
        </div>
      )}

      <style>{`
        @keyframes zoomIn {
          from { transform: scale(0.9); opacity: 0; }
          to { transform: scale(1); opacity: 1; }
        }
        .animate-zoomIn {
          animation: zoomIn 0.5s cubic-bezier(0.16, 1, 0.3, 1) forwards;
        }
      `}</style>
    </div>
  );
};

export default SocialAssets;
